var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"메이슨 씨, 메이슨 씨......","JPN":"はあ、メイソンさん……？","ENG":"Mr. Mason, Mr. Mason...","TWN":"梅森，梅森先生……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"이것 참......쉽게 쉽게 가자니까 자꾸 일을 어렵게 만드시네.","JPN":"やれやれ……どうして簡単に終わることをこじらせてしまうんだか。","ENG":"I really wanted to keep things simple... and you just had to make everything complicated.","TWN":"這可真是……本來想簡單了事的，怎麼老是把事情搞得這麼複雜。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"정말이지, 덕분에 옷이 더러워졌잖아요.","JPN":"まったく、おかげで服が汚れたじゃないですか。","ENG":"You got my clothes dirty, for gosh sake.","TWN":"真是的，拜你所賜，我的衣服都弄髒了。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"이 옷 얼만지 아세요? 제가 이거 구한다고 얼마나 고생을......","JPN":"この服がいくらすると思います？\\nこれを手に入れようとかなり苦労したのに……","ENG":"Do you have any idea how much this cost me? I had to go through hell to get this...","TWN":"你知道這件衣服要多少錢嗎？我為了買它費了多少力氣……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"말하는 도중에 사람 머리에 총을 쏘다니. 버릇이 참 나쁘시네.","JPN":"人が話しているのに頭を撃つなんて。悪い癖ですよ。","ENG":"How could you shoot someone while they’re still talking? That’s rude.","TWN":"竟然會在說話的時候，對著別人的腦袋開槍？這可真是個壞習慣。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"탄약 더 없어?","JPN":"弾薬、もっとないか？","ENG":"Got any more ammo?","TWN":"還有彈藥嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"간당간당해!","JPN":"ギリギリだ！","ENG":"We're running out!","TWN":"沒多少了！"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"몰려온 침식체들도 거의 전멸이야!","JPN":"押し寄せてきた侵食体もほぼ全滅だ！","ENG":"Most of the C.O.'s have been wiped out too!","TWN":"湧過來的侵蝕體也幾乎全滅了！"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"저 자식은 무슨 탱크 같은 건가...... 그걸 다 몰살시키다니 말이 돼, 이게?","JPN":"あいつは戦車か何かか……？\\nあれを全滅させるなんてあり得ないだろ？","ENG":"Is he some kind of a tank? How the hell did he kill all of them by himself?","TWN":"那傢伙是坦克嗎……竟然把那些侵蝕體都消滅了，這還像話嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"아까도 그렇고 지금도 그렇고......","JPN":"さっきもそうだし、今もそうだし……","ENG":"I can’t believe you managed to do that again...","TWN":"剛才也是，現在也是……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"도대체 침식체들은 어떻게 모아온 겁니까? 귀찮게시리.","JPN":"侵食体はどうやって集めてきたんです？\\nよくもまあ面倒をかけてくれましたね。","ENG":"How did you lure all those C.O.'s here? That was rather annoying.","TWN":"你們到底是怎麼把侵蝕體弄來的？真是麻煩。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"이래서 내가 용병 나부랭이들을 좋아할 수가 없다니까.","JPN":"これだから傭兵は好きになれないんですよ。","ENG":"This is why I can never get myself to like these mercenary losers.","TWN":"這就是我不喜歡傭兵的理由。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"응? 그런데 그 여자 분은 안 보이는군요.","JPN":"おや？　ところで、あの女性の方が見当たりませんね。","ENG":"Huh? I don’t see the lady with you.","TWN":"嗯？話說，我好像沒看見那位女士呢。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"같이 있는 거 아니었나요?","JPN":"一緒にいませんでしたか？","ENG":"She's not with you?","TWN":"她沒和你們沒在一起嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"여자? 누구, 제인?","JPN":"女？　ジェーンのことか？","ENG":"What lady? Jane?","TWN":"女士？誰？你說珍妮？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"......뭐, 지금은 그런 이름이었던 것 같기도 하네요.","JPN":"……ええまあ、たしか今はそんな名前だった気がしますね。","ENG":"I guess that's her name. Yes.","TWN":"……這，好像就是那個名字吧。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};